## Why this change

**Problem 1: Hot restart messages vanish**
- User calls `gateway_restart()`, the system shuts down and restarts
- On startup, boot.ts calls `handleChat()` with the restart context (line 139-145 in boot.ts)
- The LLM generates a response (line 146)
- But the response is **never added to session history** via `addMessage()`
- Result: The message appears in console logs but never reaches the user's web UI or Telegram

**Problem 2: BOOT.md messages disappear unless in fresh session**
- Same issue: chat-helpers.ts line 458 calls `_handleChat()` with boot context
- Response is generated (line 458)
- But **never persisted** with `addMessage()`
- Broadcast sends `boot_greeting` to WebSocket (line 460) but **never to Telegram**
- The message only shows up if you open a blank new chat window because the boot-startup session never gets history

**Problem 3: Boot sessions aren't tagged/identifiable**
- Both flows hardcode `'boot-startup'` as sessionId (boot.ts line 141 defaults, chat-helpers.ts line 198)
- This means every boot overwrites the same session
- User can't see which boot message is which, and can't tag them

## Exact source edits

### Edit 1: boot.ts — Persist hot restart message to session history

**File:** src/gateway/boot.ts
**Lines:** 138-148

**Before:**
```typescript
      const prompt = buildHotRestartPrompt(restartCtx, workspacePath);
      const result = await handleChat(
        prompt,
        restartCtx.previousSessionId || 'boot-startup',
        (evt, data) => {
          if (evt === 'tool_call') console.log(`[boot-md] -> ${String(data?.action || 'unknown')}`);
        },
      );
      const finalText = String(result.text || '');
      console.log(`[boot-md] Hot restart complete: ${finalText.slice(0, 120)}`);
      return { status: 'ran', reply: finalText };
```

**After:**
```typescript
      const sessionId = restartCtx.previousSessionId || 'boot-startup';
      const prompt = buildHotRestartPrompt(restartCtx, workspacePath);
      const result = await handleChat(
        prompt,
        sessionId,
        (evt, data) => {
          if (evt === 'tool_call') console.log(`[boot-md] -> ${String(data?.action || 'unknown')}`);
        },
      );
      const finalText = String(result.text || '');
      // Persist the response to session history so it appears in UI and Telegram
      const { addMessage } = await import('./session');
      addMessage(sessionId, {
        role: 'assistant',
        content: finalText,
        timestamp: Date.now(),
      }, { disableAutoSave: false });

      // Notify Telegram if this was triggered from Telegram originally
      if (restartCtx.previousTelegramChatId && restartCtx.previousTelegramUserId) {
        try {
          const { _telegramChannel } = require('./chat/chat-helpers');
          if (_telegramChannel?.sendMessage) {
            await _telegramChannel.sendMessage(
              restartCtx.previousTelegramChatId,
              `🔄 **Gateway Restart Successful**\n\n${finalText}`,
            );
          }
        } catch (err: any) {
          console.warn(`[boot-md] Telegram notification failed: ${err?.message}`);
        }
      }

      console.log(`[boot-md] Hot restart complete: ${finalText.slice(0, 120)}`);
      return { status: 'ran', reply: finalText };
```

### Edit 2: chat-helpers.ts — Persist boot message and support Boot tagging

**File:** src/gateway/chat/chat-helpers.ts
**Lines:** 443-464

**Before:**
```typescript
hookBus.register('gateway:startup', async ({ workspacePath }) => {
  const bootSessionId = 'boot-startup';
  setWorkspace(bootSessionId, workspacePath);
  clearHistory(bootSessionId);
  const startupSnapshot = buildBootStartupSnapshot(workspacePath);
  await runBootMd(workspacePath, async (message, sessionId, sendSSE) => {
    const bootContext = [
      'CONTEXT: Internal startup BOOT.md turn. All data has been pre-fetched and is in the snapshot below.',
      'Do NOT call any tools. Read the snapshot and write a 2-3 sentence startup summary.',
      '[BOOT STARTUP SNAPSHOT - pre-fetched runtime data, no tools needed]',
      startupSnapshot,
      '[/BOOT STARTUP SNAPSHOT]',
    ].join('\n\n');
    const effectiveSessionId = sessionId || bootSessionId;
    setWorkspace(effectiveSessionId, workspacePath);
    const result = await _handleChat(message, effectiveSessionId, sendSSE, undefined, undefined, bootContext);
    if (result?.text) {
      broadcastWS({ type: 'boot_greeting', text: result.text, sessionId: effectiveSessionId });
    }
    return { text: result.text };
  });
});
```

**After:**
```typescript
hookBus.register('gateway:startup', async ({ workspacePath }) => {
  // Create timestamped Boot session instead of reusing 'boot-startup'
  // Format: boot_YYYY-MM-DD_HH-mm-ss so each boot is uniquely identifiable
  const now = new Date();
  const bootSessionId = `boot_${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}_${String(now.getHours()).padStart(2, '0')}-${String(now.getMinutes()).padStart(2, '0')}-${String(now.getSeconds()).padStart(2, '0')}`;
  setWorkspace(bootSessionId, workspacePath);
  clearHistory(bootSessionId);
  const startupSnapshot = buildBootStartupSnapshot(workspacePath);
  await runBootMd(workspacePath, async (message, sessionId, sendSSE) => {
    const bootContext = [
      'CONTEXT: Internal startup BOOT.md turn. All data has been pre-fetched and is in the snapshot below.',
      'Do NOT call any tools. Read the snapshot and write a 2-3 sentence startup summary.',
      '[BOOT STARTUP SNAPSHOT - pre-fetched runtime data, no tools needed]',
      startupSnapshot,
      '[/BOOT STARTUP SNAPSHOT]',
    ].join('\n\n');
    const effectiveSessionId = sessionId || bootSessionId;
    setWorkspace(effectiveSessionId, workspacePath);
    const result = await _handleChat(message, effectiveSessionId, sendSSE, undefined, undefined, bootContext);
    if (result?.text) {
      // Persist response to session history
      addMessage(effectiveSessionId, {
        role: 'assistant',
        content: result.text,
        timestamp: Date.now(),
      }, { disableAutoSave: false });

      // Broadcast to WebSocket UI
      broadcastWS({ type: 'boot_greeting', text: result.text, sessionId: effectiveSessionId });

      // Tag this session as a Boot session in metadata so UI can filter/label it
      // This persists in the session file so the Boot tag survives restarts
      const session = getSession(effectiveSessionId);
      if (!session.tags) (session as any).tags = [];
      if (!(session as any).tags.includes('Boot')) {
        (session as any).tags.push('Boot');
      }
    }
    return { text: result.text };
  });
});
```

